import { Box, Button, FormHelperText, FormLabel, TextField, Typography } from '@material-ui/core'
import React from 'react'

function EditAccount() {
    
    const [data, setData] = useState({
        currentPassword: '',
        newPassword: '',
        repeatNewPassword: ''
    });

    const handleChange = () => {
        console.log(data.currentPassword);
        console.log(data.newPassword);
        console.log(data.repeatNewPassword);
    }


    return (
        <Box>
            <Typography variant='h3' >
                Change Password
            </Typography>
            <form>


            <FormHelperText>Enter your password to confirm.</FormHelperText>
                <TextField
                    variant='outlined'
                    placeholder='Current Password'
                    name='currentPassword'
                    value={data.currentPassword}
                    onChange={handleChange}
                    fullWidth
                />

                <br />
                <br />
                <br />

                <TextField
                    variant='outlined'
                    placeholder='New Password'
                    name='newPassword'
                    value={data.newPassword}
                    onChange={handleChange}
                    fullWidth
                />

                <br />
                <br />
                <TextField
                    variant='outlined'
                    placeholder='Repeat New Password'
                    name='repeatNewPassword'
                    value={data.repeatNewPassword}
                    onChange={handleChange}
                    fullWidth
                />

                <br />
                <br />

                <Button variant='contained' color='secondary' fullWidth >
                    Confirm changes
                </Button>
            </form>
        </Box>
    )
}

export default EditAccount
